import{_ as r,o as e,c as a,a as t}from"./app-2c7e8012.js";const b={},h=t('<h2 id="冷冷清清的风风火火" tabindex="-1"><a class="header-anchor" href="#冷冷清清的风风火火" aria-hidden="true">#</a> 冷冷清清的风风火火</h2><p>终于在历经 400 多天后<br> 重新回到了这座承载着我初心的小岛<br> 那么的冷冷清清<br> 又是那么的风风火火<br> 好久不见 你好吗</p><h2 id="万头攒动火树银花之处不必找我" tabindex="-1"><a class="header-anchor" href="#万头攒动火树银花之处不必找我" aria-hidden="true">#</a> 万头攒动火树银花之处不必找我</h2><p>在现场听一场吉他指弹演出是一件特别容易使人感动的事<br> 我本来就是个特别容易被感同身受的人<br> 在无数个难眠的夜晚<br> 被纯粹的吉他曲子感动<br> 也常常会在拥挤的地铁上<br> 不禁想那些行人耳机里播放着什么样的曲子<br> 是能够轻松剥开人的外壳的摇滚吗？ 吼出了谁的灵魂呢？<br> 还是和我一样听着无词的歌<br> 隐没在自己的小小世界<br> 任由那些有人分享的回忆 变得念念不忘<br> 我翻开备忘录<br> 关于木心 他说<br> 「万头攒动火树银花之处不必找我」<br> 「如欲相见 我在悲喜交集处」</p><h2 id="从前慢" tabindex="-1"><a class="header-anchor" href="#从前慢" aria-hidden="true">#</a> 从前慢</h2><p>三年后，经常觉得很多人是在假装生活<br> 假装去上班，假装拿一份工资，假装快乐<br> 假装有奔头，假装一个情绪平稳的正常人<br> fake it till you make it<br> 如果不这样，可能无法把生活过下去</p><p>但偶尔抬头看到夕阳余晖的时候<br> 看到满月升起的时候<br> 感到一阵微风吹过的时候<br> 还是会鼻酸 然后叹一口气<br> 在这个草台班子构成的世界里<br> 尽到本分，继续扮演自己的角色</p><h2 id="我忘怀自己时" tabindex="-1"><a class="header-anchor" href="#我忘怀自己时" aria-hidden="true">#</a> 我忘怀自己时</h2><p>竹竹最近说：</p><p>“以前是享受生活并记录，最近是想靠记录踹自己一脚恢复“正常人生活”。”</p><p>「你下班以後乾的事情也不是興趣愛好，其實是你的畢生追求，你只是害怕失敗，你想『隨便玩玩』，你不敢設定目標。」</p><p>我最近才开始思考那些忘怀自己的时刻</p><p>是什么时候呢？</p>',13),d=[h];function i(n,c){return e(),a("div",null,d)}const s=r(b,[["render",i],["__file","newStart.html.vue"]]);export{s as default};
